  1	import * as React from 'react';
  2	import {
  3	  DualListSelector,
  4	  DualListSelectorControlsWrapper,
  5	  DualListSelectorControl,
  6	  SearchInput,
  7	} from '@patternfly/react-core';
  8	import {
  9	  AngleDoubleLeftIcon,
 10	  AngleDoubleRightIcon,
 11	  AngleLeftIcon,
 12	  AngleRightIcon,
 13	} from '@patternfly/react-icons';
 14	
 15	export const CustomDualListSelector = ({
 16	  availableOptions,
 17	  setAvailableOptions,
 18	  chosenOptions,
 19	  setChosenOptions,
 20	  DualListSelectorAvailablePane,
 21	  DualListSelectorChosenPane,
 22	  searchFilterCondition,
 23	  state = undefined,
 24	  dispatch = undefined,
 25	}) => {
 26	  const [availableFilter, setAvailableFilter] = React.useState('');
 27	  const [chosenFilter, setChosenFilter] = React.useState('');
 28	
 29	  // callback for moving selected options between lists
 30	  const moveSelected = (fromAvailable: boolean) => {
 31	    const sourceOptions = fromAvailable ? availableOptions : chosenOptions;
 32	    const destinationOptions = fromAvailable ? chosenOptions : availableOptions;
 33	    for (let i = 0; i < sourceOptions.length; i++) {
 34	      const option = sourceOptions[i];
 35	      if (option.selected && option.isVisible) {
 36	        sourceOptions.splice(i, 1);
 37	        destinationOptions.push(option);
 38	        option.selected = false;
 39	        i--;
 40	      }
 41	    }
 42	    if (fromAvailable) {
 43	      setAvailableOptions([...sourceOptions]);
 44	      setChosenOptions([...destinationOptions]);
 45	    } else {
 46	      setChosenOptions([...sourceOptions]);
 47	      setAvailableOptions([...destinationOptions]);
 48	    }
 49	  };
 50	
 51	  // callback for moving all options between lists
 52	  const moveAll = (fromAvailable: boolean) => {
 53	    if (fromAvailable) {
 54	      setChosenOptions([
 55	        ...availableOptions.filter((option) => option.isVisible),
 56	        ...chosenOptions,
 57	      ]);
 58	      setAvailableOptions([
 59	        ...availableOptions.filter((option) => !option.isVisible),
 60	      ]);
 61	    } else {
 62	      setAvailableOptions([
 63	        ...chosenOptions.filter((option) => option.isVisible),
 64	        ...availableOptions,
 65	      ]);
 66	      setChosenOptions([
 67	        ...chosenOptions.filter((option) => !option.isVisible),
 68	      ]);
 69	    }
 70	  };
 71	
 72	  // callback when option is selected
 73	  const onOptionSelect = (
 74	    _event: React.MouseEvent | React.ChangeEvent | React.KeyboardEvent,
 75	    index: number,
 76	    isChosen: boolean
 77	  ) => {
 78	    if (isChosen) {
 79	      const newChosen = [...chosenOptions];
 80	      newChosen[index].selected = !chosenOptions[index].selected;
 81	      setChosenOptions(newChosen);
 82	    } else {
 83	      const newAvailable = [...availableOptions];
 84	      newAvailable[index].selected = !availableOptions[index].selected;
 85	      setAvailableOptions(newAvailable);
 86	    }
 87	  };
 88	
 89	  // builds a search input - used in each dual list selector pane
 90	  const buildSearchInput = (isAvailable: boolean) => {
 91	    // **Note: PatternFly change the fn signature
 92	    // From: (value: string, event: React.FormEvent<HTMLInputElement>) => void
 93	    // To: (_event: React.FormEvent<HTMLInputElement>, value: string) => void
 94	    // both cases need to be handled for backwards compatibility
 95	    const onChange = (input: any) => {
 96	      const value =
 97	        typeof input === 'string'
 98	          ? input
 99	          : (input.target as HTMLInputElement).value;
100	      isAvailable ? setAvailableFilter(value) : setChosenFilter(value);
101	      const toFilter = isAvailable ? [...availableOptions] : [...chosenOptions];
102	      toFilter.forEach((option) => {
103	        option.isVisible = value === '' || searchFilterCondition(option, value);
104	      });
105	    };
106	
107	    return (
108	      <SearchInput
109	        value={isAvailable ? availableFilter : chosenFilter}
110	        onChange={onChange}
111	        onClear={() => onChange('')}
112	      />
113	    );
114	  };
115	
116	  return (
117	    <DualListSelector>
118	      <DualListSelectorAvailablePane
119	        availableOptions={availableOptions}
120	        chosenOptions={chosenOptions}
121	        buildSearchInput={buildSearchInput}
122	        onOptionSelect={onOptionSelect}
123	        state={state}
124	        dispatch={dispatch}
125	      />
126	      <DualListSelectorControlsWrapper>
127	        <DualListSelectorControl
128	          isDisabled={!availableOptions.some((option) => option.selected)}
129	          onClick={() => moveSelected(true)}
130	          aria-label="Add selected"
131	          tooltipContent="Add selected"
132	        >
133	          <AngleRightIcon />
134	        </DualListSelectorControl>
135	        <DualListSelectorControl
136	          isDisabled={availableOptions.length === 0}
137	          onClick={() => moveAll(true)}
138	          aria-label="Add all"
139	          tooltipContent="Add all"
140	        >
141	          <AngleDoubleRightIcon />
142	        </DualListSelectorControl>
143	        <DualListSelectorControl
144	          isDisabled={chosenOptions.length === 0}
145	          onClick={() => moveAll(false)}
146	          aria-label="Remove all"
147	          tooltipContent="Remove all"
148	        >
149	          <AngleDoubleLeftIcon />
150	        </DualListSelectorControl>
151	        <DualListSelectorControl
152	          onClick={() => moveSelected(false)}
153	          isDisabled={!chosenOptions.some((option) => option.selected)}
154	          aria-label="Remove selected"
155	          tooltipContent="Remove selected"
156	        >
157	          <AngleLeftIcon />
158	        </DualListSelectorControl>
159	      </DualListSelectorControlsWrapper>
160	      <DualListSelectorChosenPane
161	        chosenOptions={chosenOptions}
162	        buildSearchInput={buildSearchInput}
163	        onOptionSelect={onOptionSelect}
164	        state={state}
165	        dispatch={dispatch}
166	      />
167	    </DualListSelector>
168	  );
169	};

